#include <bits/stdc++.h>
using namespace std;

int q;

int max_fac(int x) {
    if (x == 1) return 0;
    if (x % 2 == 0) return x / 2;
    for (int i = 3; i * i <= x; i += 2) {
        if (x % i == 0) {
            return x / i;
        }
    }
    return 1;
}

vector<int> father(int x) {
    vector<int> fa;
    while (x != 0) {
        fa.push_back(x);
        x = max_fac(x);
    }
    return fa;
}

int solve(int x, int y) {
    vector<int> fx, fy;
    fx = father(x), fy = father(y);
    int i = fx.size() - 1;
    int j = fy.size() - 1;
    while (i >= 0 && j >= 0 && fx[i] == fy[j]) {
        i--, j--;
    }
    return i + j + 2;
}

int main() {
    cin >> q;
    while (q--) {
        int x, y;
        cin >> x >> y;
        cout << solve(x, y) << endl;
    }
    return 0;
}
